SELECT id, msg_type, from_user_id, to_user_id, group_id, body, created_at FROM im_messages WHERE msg_type = 'P2P' AND ((from_user_id = #{userId} AND to_user_id = #{peerUserId}) OR (from_user_id = #{peerUserId} AND to_user_id = #{userId}))
AND id < #{beforeId}
ORDER BY id DESC LIMIT #{limit}

SELECT id, msg_type, from_user_id, to_user_id, group_id, body, created_at
FROM im_messages
WHERE msg_type = 'GROUP' AND group_id = #{groupId}

    AND id < #{beforeId}

ORDER BY id DESC
LIMIT #{limit}
